"""Signed, time-limited OAuth `state` payloads for CSRF protection (Google and Slack)."""

from __future__ import annotations

import base64
import hashlib
import hmac
import json
import secrets
import time
import uuid

from core.config import settings


def _encode(data: dict) -> str:
    """Serialize `data` to a URL-safe string with HMAC integrity."""
    body = json.dumps(data, sort_keys=True, separators=(",", ":")).encode("utf-8")
    sig = hmac.new(settings.SECRET_KEY.encode("utf-8"), body, hashlib.sha256).digest()
    blob = body + b"\x00" + sig
    return base64.urlsafe_b64encode(blob).decode("ascii").rstrip("=")


def _decode(token: str, max_age_sec: int) -> dict | None:
    """Verify HMAC and max age; return the JSON payload or None."""
    if not token:
        return None
    pad = "=" * (-len(token) % 4)
    try:
        blob = base64.urlsafe_b64decode((token + pad).encode("ascii"))
    except (ValueError, UnicodeDecodeError):
        return None
    if b"\x00" not in blob:
        return None
    body, sig = blob.rsplit(b"\x00", 1)
    expected = hmac.new(settings.SECRET_KEY.encode("utf-8"), body, hashlib.sha256).digest()
    if not hmac.compare_digest(expected, sig):
        return None
    try:
        data = json.loads(body.decode("utf-8"))
    except json.JSONDecodeError:
        return None
    ts = int(data.get("t", 0))
    if int(time.time()) - ts > max_age_sec:
        return None
    return data


def create_google_oauth_state() -> str:
    """Build a signed `state` value for the Google authorize URL."""
    return _encode(
        {
            "p": "google",
            "t": int(time.time()),
            "n": secrets.token_urlsafe(16),
        }
    )


def verify_google_oauth_state(state: str) -> bool:
    """Return True if `state` is a valid, unexpired Google OAuth state."""
    data = _decode(state, max_age_sec=600)
    return bool(data and data.get("p") == "google" and data.get("n"))


def create_slack_oauth_state(user_id: uuid.UUID) -> str:
    """Build a signed `state` tying this Slack install to a Chrona user."""
    return _encode({"p": "slack", "t": int(time.time()), "uid": str(user_id)})


def verify_slack_oauth_state(state: str) -> uuid.UUID | None:
    """Return the Chrona user id from Slack `state`, or None if invalid."""
    data = _decode(state, max_age_sec=600)
    if not data or data.get("p") != "slack" or not data.get("uid"):
        return None
    try:
        return uuid.UUID(str(data["uid"]))
    except ValueError:
        return None

"""JWT session tokens and Fernet encryption for stored OAuth secrets."""

from __future__ import annotations

from datetime import UTC, datetime, timedelta

from cryptography.fernet import Fernet, InvalidToken
from fastapi import HTTPException
from jose import JWTError, jwt

from core.config import settings


def create_access_token(user_id: str, email: str) -> str:
    """Create a signed JWT for API access. Expires in 7 days (MVP, no refresh)."""
    expire = datetime.now(UTC) + timedelta(days=7)
    payload = {"sub": user_id, "email": email, "exp": expire}
    return jwt.encode(payload, settings.SECRET_KEY, algorithm="HS256")


def decode_access_token(token: str) -> dict:
    """Decode and validate a JWT. Raises HTTP 401 on any failure."""
    try:
        return jwt.decode(token, settings.SECRET_KEY, algorithms=["HS256"])
    except JWTError as exc:
        raise HTTPException(status_code=401, detail="Invalid or expired token") from exc


def encrypt_token(plain: str) -> str:
    """Encrypt a token or secret for storage in the database (Fernet)."""
    f = Fernet(settings.ENCRYPTION_KEY.encode("utf-8"))
    return f.encrypt(plain.encode("utf-8")).decode("ascii")


def decrypt_token(encrypted: str) -> str:
    """Decrypt a value previously stored with :func:`encrypt_token`."""
    f = Fernet(settings.ENCRYPTION_KEY.encode("utf-8"))
    try:
        return f.decrypt(encrypted.encode("ascii")).decode("utf-8")
    except InvalidToken as exc:
        raise HTTPException(status_code=500, detail="Failed to decrypt stored token") from exc

