router = APIRouter()


@router.get("/google")
async def google_oauth_start() -> RedirectResponse:
    """Redirect the browser to Google OAuth (no auth required)."""
    state = auth_service.new_google_oauth_state()
    url = auth_service.build_google_authorize_url(state)
    return RedirectResponse(url, status_code=302)


@router.get("/google/callback")
async def google_oauth_callback(
    db: AsyncSession = Depends(get_db),
    code: str | None = None,
    state: str | None = None,
    error: str | None = None,
) -> RedirectResponse:
    """Handle Google redirect: create/update user, store tokens, redirect with JWT."""
    if error:
        q = quote(str(error), safe="")
        return RedirectResponse(f"{settings.FRONTEND_URL}/login?error={q}", status_code=302)
    if not state or not verify_google_oauth_state(state):
        return RedirectResponse(
            f"{settings.FRONTEND_URL}/login?error=invalid_state",
            status_code=302,
        )
    if not code:
        return RedirectResponse(
            f"{settings.FRONTEND_URL}/login?error=missing_code",
            status_code=302,
        )
    user = await auth_service.complete_google_oauth(db, code=code)
    url = auth_service.post_google_login_redirect(user)
    return RedirectResponse(url, status_code=302)


@router.get("/slack")
async def slack_oauth_start(current_user: User = Depends(get_current_user)) -> RedirectResponse:
    """Redirect the browser to Slack OAuth (requires Chrona JWT)."""
    state = auth_service.new_slack_oauth_state(current_user)
    url = auth_service.build_slack_authorize_url(state)
    return RedirectResponse(url, status_code=302)


@router.get("/slack/callback")
async def slack_oauth_callback(
    db: AsyncSession = Depends(get_db),
    code: str | None = None,
    state: str | None = None,
    error: str | None = None,
) -> RedirectResponse:
    """Handle Slack redirect: store bot token and Slack user id, redirect with JWT."""
    if error:
        q = quote(str(error), safe="")
        return RedirectResponse(f"{settings.FRONTEND_URL}/login?error={q}", status_code=302)
    if not state:
        return RedirectResponse(
            f"{settings.FRONTEND_URL}/login?error=invalid_state",
            status_code=302,
        )
    user_id = verify_slack_oauth_state(state)
    if user_id is None:
        return RedirectResponse(
            f"{settings.FRONTEND_URL}/login?error=invalid_state",
            status_code=302,
        )
    if not code:
        return RedirectResponse(
            f"{settings.FRONTEND_URL}/login?error=missing_code",
            status_code=302,
        )
    user = await auth_service.complete_slack_oauth(db, user_id=user_id, code=code)
    url = auth_service.post_slack_login_redirect(user)
    return RedirectResponse(url, status_code=302)


