def verify_slack_signature(request_body: bytes, timestamp: str, signature: str) -> bool:
    """
    Verify ``X-Slack-Signature`` for an interactive component request.

    Uses ``sig_basestring = "v0:{timestamp}:{body}"`` and HMAC-SHA256 with
    ``SLACK_SIGNING_SECRET``. Rejects stale timestamps to limit replay attacks.
    """
    if not timestamp or not signature or not signature.startswith("v0="):
        return False
    try:
        request_ts = int(timestamp)
    except ValueError:
        return False
    if abs(time.time() - request_ts) > SLACK_SIGNATURE_MAX_AGE_SECONDS:
        return False
    body_text = request_body.decode("utf-8")
    sig_basestring = f"v0:{timestamp}:{body_text}"
    digest = hmac.new(
        settings.SLACK_SIGNING_SECRET.encode("utf-8"),
        sig_basestring.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()
    expected = f"v0={digest}"
    return hmac.compare_digest(expected, signature)

