"""Slack interactive webhook handling (approve / dismiss / stubs)."""

from __future__ import annotations

import json
import uuid
from typing import Any
from urllib.parse import parse_qs

from fastapi import HTTPException
from sqlalchemy.ext.asyncio import AsyncSession

from db.crud import preferences
from services import task_service

ACTION_APPROVE = "approve_task"
ACTION_DISMISS = "dismiss_task"
ACTION_EDIT_TIME = "edit_task_time"


def parse_slack_interactive_payload(body: bytes) -> dict[str, Any]:
    """Parse URL-encoded form body and return the JSON ``payload`` object."""
    form = parse_qs(body.decode("utf-8"), keep_blank_values=True)
    raw_list = form.get("payload")
    if not raw_list or not raw_list[0]:
        raise HTTPException(status_code=400, detail="Missing Slack payload")
    try:
        data = json.loads(raw_list[0])
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail="Invalid Slack payload JSON") from exc
    if not isinstance(data, dict):
        raise HTTPException(status_code=400, detail="Slack payload must be a JSON object")
    return data


def _extract_action(payload: dict[str, Any]) -> tuple[str, uuid.UUID, str]:
    """Return ``(action_id, task_id, slack_user_id)`` from an interactive payload."""
    actions = payload.get("actions")
    if not isinstance(actions, list) or not actions:
        raise HTTPException(status_code=400, detail="Slack payload missing actions")
    action = actions[0]
    if not isinstance(action, dict):
        raise HTTPException(status_code=400, detail="Invalid Slack action")
    action_id = action.get("action_id")
    value = action.get("value")
    if not action_id or not value:
        raise HTTPException(status_code=400, detail="Slack action missing action_id or value")
    user = payload.get("user")
    if not isinstance(user, dict) or not user.get("id"):
        raise HTTPException(status_code=400, detail="Slack payload missing user id")
    try:
        task_id = uuid.UUID(str(value))
    except ValueError as exc:
        raise HTTPException(status_code=400, detail="Invalid task id in Slack action") from exc
    return str(action_id), task_id, str(user["id"])


def slack_ephemeral_response(text: str) -> dict[str, str]:
    """Build a Slack-compatible JSON body for an ephemeral message."""
    return {"response_type": "ephemeral", "text": text}


def slack_empty_ack() -> dict[str, str]:
    """Acknowledge the interaction without updating the message."""
    return {}


async def handle_slack_interactive(db: AsyncSession, payload: dict[str, Any]) -> dict[str, str]:
    """
    Route a verified Slack interactive payload to approve, dismiss, or stub handlers.

    Returns a JSON dict suitable as the HTTP response body (always prefer 200 to Slack).
    """
    action_id, task_id, slack_user_id = _extract_action(payload)
    user_id = await preferences.get_user_id_by_slack_user_id(db, slack_user_id)
    if user_id is None:
        return slack_ephemeral_response(
            "Your Slack account is not linked to Chrona. Complete Slack OAuth in onboarding."
        )

    if action_id == ACTION_EDIT_TIME:
        return slack_ephemeral_response("Editing task time from Slack is not available yet.")

    try:
        if action_id == ACTION_APPROVE:
            await task_service.approve_task(db, user_id, task_id)
            return slack_ephemeral_response("Task approved. The agent will schedule it shortly.")
        if action_id == ACTION_DISMISS:
            await task_service.dismiss_task(db, user_id, task_id)
            return slack_ephemeral_response("Task dismissed.")
    except HTTPException as exc:
        detail = exc.detail if isinstance(exc.detail, str) else "Could not update task"
        return slack_ephemeral_response(detail)

    return slack_ephemeral_response(f"Unknown action: {action_id}")
